import Lenis from 'lenis';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

export function initSmoothScroll() {
  const lenis = new Lenis({
    duration: 1.35,
    easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
    smoothWheel: true,
    touchMultiplier: 1.2,
  });

  lenis.on('scroll', ScrollTrigger.update);

  gsap.ticker.add((time) => {
    lenis.raf(time * 1000);
  });
  gsap.ticker.lagSmoothing(0);

  return lenis;
}

export function scrollTo(target, lenis) {
  if (lenis && typeof lenis.scrollTo === 'function') {
    lenis.scrollTo(target, { duration: 1.8 });
    return;
  }
  target?.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

export function triggerPreloaderBurst(canvas) {
  if (!canvas) return;

  const ctx = canvas.getContext('2d');
  const cx = canvas.width / 2;
  const cy = canvas.height / 2;
  const particles = [];
  const colors = ['#00d4ff', '#8b5cf6', '#e8e8f0'];

  for (let i = 0; i < 120; i++) {
    const angle = (Math.PI * 2 * i) / 120 + Math.random() * 0.2;
    const speed = 2 + Math.random() * 6;
    particles.push({
      x: cx,
      y: cy,
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed,
      life: 1,
      decay: 0.012 + Math.random() * 0.01,
      r: 1.5 + Math.random() * 3,
      color: colors[Math.floor(Math.random() * colors.length)],
    });
  }

  let raf;
  const draw = () => {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    let alive = 0;

    particles.forEach((p) => {
      if (p.life <= 0) return;
      alive++;
      p.x += p.vx;
      p.y += p.vy;
      p.vx *= 0.98;
      p.vy *= 0.98;
      p.life -= p.decay;

      ctx.beginPath();
      ctx.arc(p.x, p.y, p.r * p.life, 0, Math.PI * 2);
      ctx.fillStyle = p.color;
      ctx.globalAlpha = p.life * 0.85;
      ctx.fill();
    });

    ctx.globalAlpha = 1;
    if (alive > 0) raf = requestAnimationFrame(draw);
    else canvas.classList.add('is-hidden');
  };

  draw();
  return () => cancelAnimationFrame(raf);
}

import gsap from 'gsap';
import { triggerPreloaderBurst } from './preloader-burst.js';

export function runPreloader(onComplete) {
  const preloader = document.getElementById('preloader');
  const progress = document.getElementById('preloader-progress');
  const letters = document.querySelectorAll('.preloader__letter');
  const burstCanvas = document.getElementById('preloader-burst');

  if (!preloader) {
    onComplete?.();
    return;
  }

  document.body.style.overflow = 'hidden';

  if (burstCanvas) {
    burstCanvas.width = window.innerWidth;
    burstCanvas.height = window.innerHeight;
  }

  const tl = gsap.timeline({
    onComplete: () => {
      triggerPreloaderBurst(burstCanvas);
      gsap.to(preloader, {
        opacity: 0,
        duration: 0.7,
        delay: 0.35,
        ease: 'power2.inOut',
        onComplete: () => {
          preloader.classList.add('is-done');
          document.body.classList.add('is-loaded');
          document.body.style.overflow = '';
          onComplete?.();
        },
      });
    },
  });

  tl.to(letters, {
    opacity: 1,
    y: 0,
    duration: 0.6,
    stagger: 0.12,
    ease: 'power3.out',
  })
    .to(
      progress,
      {
        width: '100%',
        duration: 1.4,
        ease: 'power2.inOut',
      },
      '-=0.2'
    )
    .to(
      '.preloader__label',
      {
        opacity: 0.4,
        duration: 0.3,
      },
      '-=0.3'
    );
}

import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { NeuralScene } from './js/neural-scene.js';
import { AboutMesh } from './js/about-mesh.js';
import { SkillsOrbit } from './js/skills-orbit.js';
import { initCursor } from './js/cursor.js';
import { runPreloader } from './js/preloader.js';
import { initTiltCards } from './js/tilt.js';
import { initFooterParticles } from './js/footer-particles.js';
import { initSmoothScroll, scrollTo } from './js/smooth-scroll.js';
import {
  splitHeroTitle,
  typeSubtitle,
  initHeroAnimations,
  initScrollAnimations,
  initHeroCTA,
  initContactForm,
  initNav,
} from './js/animations.js';

gsap.registerPlugin(ScrollTrigger);

const isMobile = window.matchMedia('(max-width: 768px), (pointer: coarse)').matches;
if (isMobile) document.body.classList.add('is-mobile');

let neuralScene;
let aboutMesh;
let skillsOrbit;
let lenis;
let scrollSection = 0;

function initThree() {
  const canvas = document.getElementById('webgl');
  if (!canvas) return;

  if (isMobile) canvas.classList.add('is-reduced');

  neuralScene = new NeuralScene(canvas, { reduced: isMobile });

  const aboutContainer = document.getElementById('about-object');
  if (aboutContainer && !isMobile) {
    aboutMesh = new AboutMesh(aboutContainer);
  }

  const skillsCanvas = document.getElementById('skills-canvas');
  if (skillsCanvas && !isMobile) {
    skillsOrbit = new SkillsOrbit(skillsCanvas);

    ScrollTrigger.create({
      trigger: '#skills',
      start: 'top bottom',
      end: 'bottom top',
      onEnter: () => skillsOrbit?.setActive(true),
      onLeave: () => skillsOrbit?.setActive(false),
      onEnterBack: () => skillsOrbit?.setActive(true),
      onLeaveBack: () => skillsOrbit?.setActive(false),
    });
  } else if (skillsCanvas) {
    const wrap = document.getElementById('skills-canvas-wrap');
    if (wrap) {
      wrap.innerHTML = `
        <motion.div class="skills-fallback">
          <div class="skills-fallback__core"></div>
          <p class="skills-fallback__text">Neural orbit · optimized view</p>
        </div>
      `.replace('motion.div', 'motion.div').replace('<motion.div', '<div').replace('</motion.div>', '</div>');
    }
  }
}

function animate() {
  requestAnimationFrame(animate);

  neuralScene?.updateCameraFromScroll(scrollSection / 4);
  neuralScene?.render();
  aboutMesh?.render();
  if (skillsOrbit?.isActive) skillsOrbit.render();
}

function bootstrap() {
  splitHeroTitle();
  initCursor();
  initTiltCards();
  initHeroCTA((target) => scrollTo(target, lenis));
  initContactForm();
  initNav(lenis);
  initFooterParticles(document.getElementById('footer-particles'));

  initScrollAnimations({
    isMobile,
    onScrollProgress: (p) => {
      scrollSection = p * 4;
      neuralScene?.setScrollProgress(p);
      const bar = document.getElementById('scroll-progress');
      if (bar) bar.style.transform = `scaleX(${p})`;
    },
  });

  ScrollTrigger.refresh();

  typeSubtitle(document.getElementById('hero-subtitle'));
  initHeroAnimations();
  animate();
}

runPreloader(() => {
  try {
    lenis = initSmoothScroll();
  } catch {
    lenis = null;
  }
  initThree();
  bootstrap();
});

import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { scrollTo } from './smooth-scroll.js';

gsap.registerPlugin(ScrollTrigger);

const SUBTITLE_TEXT = 'AI Developer · LLM Engineer · Systems Builder';

export function splitHeroTitle() {
  const lines = document.querySelectorAll('.hero__title [data-split]');
  lines.forEach((line) => {
    const text = line.textContent;
    line.textContent = '';
    text.split('').forEach((char) => {
      const span = document.createElement('span');
      span.className = 'char';
      span.textContent = char === ' ' ? '\u00A0' : char;
      line.appendChild(span);
    });
  });
}

export function typeSubtitle(el) {
  if (!el) return;
  let i = 0;
  const tick = () => {
    if (i <= SUBTITLE_TEXT.length) {
      el.textContent = SUBTITLE_TEXT.slice(0, i);
      i++;
      setTimeout(tick, i === SUBTITLE_TEXT.length ? 400 : 45);
    } else {
      el.classList.add('is-done');
    }
  };
  setTimeout(tick, 900);
}

export function initHeroAnimations() {
  const tl = gsap.timeline({ delay: 0.15 });

  tl.to('.site-nav', { opacity: 1, y: 0, duration: 0.8, ease: 'power3.out' })
    .to('.hero__eyebrow', { opacity: 1, y: 0, duration: 0.8, ease: 'power3.out' }, '-=0.5')
    .to(
      '.hero__title .char',
      {
        opacity: 1,
        y: 0,
        rotateX: 0,
        duration: 0.9,
        stagger: 0.025,
        ease: 'power4.out',
      },
      '-=0.4'
    )
    .to('#hero-cta', { opacity: 1, y: 0, duration: 0.7, ease: 'power3.out' }, '-=0.3')
    .to('.hero__scroll-hint', { opacity: 1, duration: 0.6 }, '-=0.2');
}

export function initNav(lenis) {
  document.querySelectorAll('.site-nav a[href^="#"]').forEach((link) => {
    link.addEventListener('click', (e) => {
      e.preventDefault();
      const id = link.getAttribute('href');
      const target = document.querySelector(id);
      scrollTo(target, lenis);
    });
  });

  const sections = ['#hero', '#about', '#projects', '#skills', '#contact'];
  sections.forEach((id) => {
    const el = document.querySelector(id);
    if (!el) return;
    ScrollTrigger.create({
      trigger: el,
      start: 'top center',
      end: 'bottom center',
      onToggle: (self) => {
        if (self.isActive) {
          document.querySelectorAll('.site-nav__link').forEach((a) => {
            a.classList.toggle('is-active', a.getAttribute('href') === id);
          });
        }
      },
    });
  });
}

export function initScrollAnimations({ onScrollProgress, isMobile = false }) {
  const sections = gsap.utils.toArray('.section');

  sections.forEach((section) => {
    gsap.from(section.querySelectorAll('.section__tag, .section__title, .section__text'), {
      scrollTrigger: {
        trigger: section,
        start: 'top 75%',
        toggleActions: 'play none none reverse',
      },
      y: 50,
      opacity: 0,
      duration: 1,
      stagger: 0.1,
      ease: 'power3.out',
    });
  });

  gsap.from('#about .about-object', {
    scrollTrigger: { trigger: '#about', start: 'top 70%', end: 'center center', scrub: 1 },
    scale: 0.6,
    opacity: 0,
    rotateY: 45,
    ease: 'none',
  });

  gsap.from('.skill-pills span', {
    scrollTrigger: { trigger: '#skill-pills', start: 'top 80%' },
    y: 20,
    opacity: 0,
    duration: 0.5,
    stagger: 0.04,
    ease: 'back.out(1.4)',
  });

  if (!isMobile) {
    const track = document.getElementById('projects-track');
    const pin = document.querySelector('.projects-pin');
    if (track && pin) {
      const getScroll = () => Math.max(0, track.scrollWidth - window.innerWidth + 80);

      gsap.to(track, {
        x: () => -getScroll(),
        ease: 'none',
        scrollTrigger: {
          trigger: '#projects',
          pin: pin,
          scrub: 1.2,
          start: 'top top',
          end: () => `+=${getScroll() + window.innerHeight * 0.5}`,
          invalidateOnRefresh: true,
          anticipatePin: 1,
        },
      });
    }
  } else {
    gsap.from('.project-card', {
      scrollTrigger: { trigger: '#projects-track', start: 'top 85%' },
      y: 40,
      opacity: 0,
      duration: 0.8,
      stagger: 0.1,
      ease: 'power3.out',
    });
  }

  gsap.from('.skills-category', {
    scrollTrigger: { trigger: '.skills-categories', start: 'top 85%' },
    y: 30,
    opacity: 0,
    duration: 0.7,
    stagger: 0.1,
    ease: 'power3.out',
  });

  gsap.from('.contact-panel', {
    scrollTrigger: { trigger: '#contact', start: 'top 75%' },
    scale: 0.95,
    opacity: 0,
    duration: 1,
    ease: 'power3.out',
  });

  document.querySelectorAll('.glitch-text').forEach((el) => {
    ScrollTrigger.create({
      trigger: el,
      start: 'top 80%',
      onEnter: () => {
        el.classList.add('is-glitching');
        setTimeout(() => el.classList.remove('is-glitching'), 400);
      },
    });
  });

  ScrollTrigger.create({
    trigger: document.documentElement,
    start: 'top top',
    end: 'bottom bottom',
    scrub: 0.6,
    onUpdate: (self) => onScrollProgress?.(self.progress),
  });
}

export function initHeroCTA(scrollFn) {
  const cta = document.getElementById('hero-cta');
  const about = document.getElementById('about');
  cta?.addEventListener('click', () => {
    if (scrollFn) scrollFn(about);
    else about?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  });
}

export function initContactForm() {
  const form = document.getElementById('contact-form');
  form?.addEventListener('submit', (e) => {
    e.preventDefault();
    const btn = form.querySelector('button');
    const original = btn.textContent;
    btn.textContent = 'Transmission sent ✓';
    btn.disabled = true;
    gsap.fromTo(btn, { scale: 1 }, { scale: 1.05, duration: 0.2, yoyo: true, repeat: 1 });
    setTimeout(() => {
      btn.textContent = original;
      btn.disabled = false;
      form.reset();
    }, 3000);
  });
}

import * as THREE from 'three';
import vertexShader from '../shaders/neural.vert?raw';
import fragmentShader from '../shaders/neural.frag?raw';

const CONNECTION_DISTANCE = 1.8;
const PARTICLE_COUNT_DESKTOP = 320;
const PARTICLE_COUNT_MOBILE = 90;

export class NeuralScene {
  constructor(canvas, { reduced = false } = {}) {
    this.canvas = canvas;
    this.reduced = reduced;
    this.mouse = new THREE.Vector2(0, 0);
    this.scrollProgress = 0;

    this.scene = new THREE.Scene();
    this.scene.fog = new THREE.FogExp2(0x0a0a0f, 0.032);

    this.camera = new THREE.PerspectiveCamera(55, 1, 0.1, 200);
    this.camera.position.set(0, 0, 12);

    this.renderer = new THREE.WebGLRenderer({
      canvas,
      antialias: !reduced,
      alpha: true,
      powerPreference: reduced ? 'low-power' : 'high-performance',
    });
    this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, reduced ? 1.5 : 2));
    this.renderer.setClearColor(0x0a0a0f, 1);

    this.clock = new THREE.Clock();
    this.orbMeshes = [];

    this._buildParticles();
    this._buildOrbs();
    this._buildLines();
    this._onResize();
    window.addEventListener('resize', () => this._onResize());
    window.addEventListener('mousemove', (e) => this._onMouseMove(e));
  }

  _particleCount() {
    return this.reduced ? PARTICLE_COUNT_MOBILE : PARTICLE_COUNT_DESKTOP;
  }

  _buildParticles() {
    const count = this._particleCount();
    const spread = this.reduced ? 14 : 24;
    const positions = new Float32Array(count * 3);
    const normals = new Float32Array(count * 3);
    const sizes = new Float32Array(count);
    const connections = new Float32Array(count);

    for (let i = 0; i < count; i++) {
      const i3 = i * 3;
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = spread * (0.25 + Math.random() * 0.75);

      positions[i3] = r * Math.sin(phi) * Math.cos(theta);
      positions[i3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      positions[i3 + 2] = r * Math.cos(phi) - 4;

      normals[i3] = (Math.random() - 0.5) * 0.12;
      normals[i3 + 1] = (Math.random() - 0.5) * 0.12;
      normals[i3 + 2] = (Math.random() - 0.5) * 0.12;

      sizes[i] = 2 + Math.random() * 5;
      connections[i] = Math.random();
    }

    this.particlePositions = positions;
    this.particleCount = count;

    const geometry = new THREE.BufferGeometry();
    geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    geometry.setAttribute('normal', new THREE.BufferAttribute(normals, 3));
    geometry.setAttribute('aSize', new THREE.BufferAttribute(sizes, 1));
    geometry.setAttribute('aConnection', new THREE.BufferAttribute(connections, 1));

    this.particleMaterial = new THREE.ShaderMaterial({
      vertexShader,
      fragmentShader,
      transparent: true,
      depthWrite: false,
      blending: THREE.AdditiveBlending,
      uniforms: {
        uTime: { value: 0 },
        uPixelRatio: { value: this.renderer.getPixelRatio() },
      },
    });

    this.particles = new THREE.Points(geometry, this.particleMaterial);
    this.scene.add(this.particles);
  }

  _buildLines() {
    const count = this.particleCount;
    const maxLines = this.reduced ? 400 : 1400;
    const linePositions = [];
    const pos = this.particlePositions;

    for (let i = 0; i < count && linePositions.length / 6 < maxLines; i++) {
      for (let j = i + 1; j < count && linePositions.length / 6 < maxLines; j++) {
        const i3 = i * 3;
        const j3 = j * 3;
        const dx = pos[i3] - pos[j3];
        const dy = pos[i3 + 1] - pos[j3 + 1];
        const dz = pos[i3 + 2] - pos[j3 + 2];
        const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);

        if (dist < CONNECTION_DISTANCE) {
          linePositions.push(pos[i3], pos[i3 + 1], pos[i3 + 2]);
          linePositions.push(pos[j3], pos[j3 + 1], pos[j3 + 2]);
        }
      }
    }

    const geometry = new THREE.BufferGeometry();
    geometry.setAttribute(
      'position',
      new THREE.Float32BufferAttribute(linePositions, 3)
    );

    const material = new THREE.LineBasicMaterial({
      color: 0x00d4ff,
      transparent: true,
      opacity: 0.09,
      blending: THREE.AdditiveBlending,
    });

    this.lines = new THREE.LineSegments(geometry, material);
    this.scene.add(this.lines);
  }

  _buildOrbs() {
    const orbCount = this.reduced ? 2 : 6;
    const geo = new THREE.IcosahedronGeometry(0.35, 0);

    for (let i = 0; i < orbCount; i++) {
      const mat = new THREE.MeshBasicMaterial({
        color: i % 2 === 0 ? 0x00d4ff : 0x8b5cf6,
        wireframe: true,
        transparent: true,
        opacity: 0.35,
      });
      const mesh = new THREE.Mesh(geo, mat);
      const angle = (i / orbCount) * Math.PI * 2;
      mesh.position.set(
        Math.cos(angle) * (4 + i * 0.5),
        Math.sin(angle * 1.3) * 2.2,
        -6 - i * 1.2
      );
      mesh.userData.base = mesh.position.clone();
      mesh.userData.phase = Math.random() * Math.PI * 2;
      this.scene.add(mesh);
      this.orbMeshes.push(mesh);
    }
  }

  _onMouseMove(e) {
    this.mouse.x = (e.clientX / window.innerWidth) * 2 - 1;
    this.mouse.y = -(e.clientY / window.innerHeight) * 2 + 1;
  }

  _onResize() {
    const w = window.innerWidth;
    const h = window.innerHeight;
    this.camera.aspect = w / h;
    this.camera.updateProjectionMatrix();
    this.renderer.setSize(w, h);
    if (this.particleMaterial) {
      this.particleMaterial.uniforms.uPixelRatio.value = this.renderer.getPixelRatio();
    }
  }

  setScrollProgress(progress) {
    this.scrollProgress = progress;
  }

  updateCameraFromScroll(sectionProgress) {
    const t = sectionProgress;
    const p = this.scrollProgress;

    const pathX = Math.sin(t * Math.PI * 0.5) * -3 + Math.sin(p * Math.PI * 2) * 0.4;
    const pathY = THREE.MathUtils.lerp(0, 2.2, t) + Math.cos(p * Math.PI) * 0.3;
    const pathZ = THREE.MathUtils.lerp(12, 5.5, Math.min(t * 1.2, 1));

    this.camera.position.x = pathX + this.mouse.x * 0.9;
    this.camera.position.y = pathY + this.mouse.y * 0.55;
    this.camera.position.z = pathZ;
    this.camera.lookAt(pathX * 0.3, pathY * 0.4, -5 - t * 2);

    const lineOpacity = 0.06 + t * 0.06;
    if (this.lines?.material) {
      this.lines.material.opacity = lineOpacity;
    }
  }

  render() {
    const elapsed = this.clock.getElapsedTime();
    this.particleMaterial.uniforms.uTime.value = elapsed;

    const scrollSpin = this.scrollProgress * 0.4;
    this.particles.rotation.y = elapsed * 0.02 + this.mouse.x * 0.1 + scrollSpin;
    this.particles.rotation.x = this.mouse.y * 0.06;
    this.lines.rotation.copy(this.particles.rotation);

    this.orbMeshes.forEach((mesh, i) => {
      const base = mesh.userData.base;
      const phase = mesh.userData.phase;
      mesh.position.x = base.x + Math.sin(elapsed * 0.5 + phase) * 0.5;
      mesh.position.y = base.y + Math.cos(elapsed * 0.4 + phase) * 0.35;
      mesh.rotation.x = elapsed * 0.3;
      mesh.rotation.y = elapsed * 0.5 + i;
      mesh.scale.setScalar(1 + Math.sin(elapsed + i) * 0.08);
    });

    this.renderer.render(this.scene, this.camera);
  }

  dispose() {
    window.removeEventListener('resize', () => this._onResize());
    this.renderer.dispose();
    this.particleMaterial.dispose();
    this.particles.geometry.dispose();
    this.lines.geometry.dispose();
    this.lines.material.dispose();
  }
}

import * as THREE from 'three';

const SKILLS = [
  'Python', 'Rust', 'C', 'React', 'Next.js', 'HTML5',
  'Node.js', 'MongoDB', 'MySQL', 'AWS', 'Firebase', 'Oracle',
];

export class SkillsOrbit {
  constructor(canvas) {
    this.canvas = canvas;
    this.labels = SKILLS;
    this.isActive = true;
    this.nodePositions = [];

    this.scene = new THREE.Scene();
    this.camera = new THREE.PerspectiveCamera(50, 1, 0.1, 100);
    this.camera.position.z = 8;

    this.renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: true });
    this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));

    const coreGeo = new THREE.SphereGeometry(0.55, 32, 32);
    const coreMat = new THREE.MeshBasicMaterial({
      color: 0x8b5cf6,
      transparent: true,
      opacity: 0.9,
    });
    this.core = new THREE.Mesh(coreGeo, coreMat);
    this.scene.add(this.core);

    const glowGeo = new THREE.SphereGeometry(0.78, 32, 32);
    const glowMat = new THREE.MeshBasicMaterial({
      color: 0x00d4ff,
      transparent: true,
      opacity: 0.1,
      wireframe: true,
    });
    this.glow = new THREE.Mesh(glowGeo, glowMat);
    this.scene.add(this.glow);

    this.nodes = [];
    const orbitRadius = 3.2;
    this.labels.forEach((label, i) => {
      const angle = (i / this.labels.length) * Math.PI * 2;
      const y = Math.sin(i * 1.7) * 1.2;
      const group = new THREE.Group();

      const dotGeo = new THREE.SphereGeometry(0.08, 12, 12);
      const dotMat = new THREE.MeshBasicMaterial({
        color: i % 2 === 0 ? 0x00d4ff : 0x8b5cf6,
      });
      const dot = new THREE.Mesh(dotGeo, dotMat);
      group.add(dot);

      const sprite = this._createLabelSprite(label);
      sprite.position.set(0, 0.28, 0);
      sprite.scale.set(1.8, 0.45, 1);
      group.add(sprite);

      group.userData = {
        angle,
        radius: orbitRadius + (i % 3) * 0.35,
        y,
        speed: 0.28 + (i % 5) * 0.05,
      };

      this.scene.add(group);
      this.nodes.push(group);
    });

    this._buildConnections();
    this.clock = new THREE.Clock();
    this._resize();
    window.addEventListener('resize', () => this._resize());
  }

  setActive(active) {
    this.isActive = active;
  }

  _createLabelSprite(text) {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    canvas.width = 256;
    canvas.height = 64;
    ctx.fillStyle = 'rgba(10, 10, 15, 0.65)';
    ctx.fillRect(0, 0, 256, 64);
    ctx.font = 'bold 26px Orbitron, sans-serif';
    ctx.fillStyle = '#00d4ff';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(text, 128, 32);

    const texture = new THREE.CanvasTexture(canvas);
    const material = new THREE.SpriteMaterial({ map: texture, transparent: true });
    return new THREE.Sprite(material);
  }

  _buildConnections() {
    const segmentCount = this.nodes.length * 2;
    const positions = new Float32Array(segmentCount * 6);

    const geo = new THREE.BufferGeometry();
    geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    const mat = new THREE.LineBasicMaterial({
      color: 0x00d4ff,
      transparent: true,
      opacity: 0.18,
    });
    this.connectionLines = new THREE.LineSegments(geo, mat);
    this.scene.add(this.connectionLines);
    this.linePositions = positions;
  }

  _resize() {
    const parent = this.canvas.parentElement;
    const w = parent.clientWidth;
    const h = parent.clientHeight;
    this.camera.aspect = w / h;
    this.camera.updateProjectionMatrix();
    this.renderer.setSize(w, h);
  }

  render() {
    const t = this.clock.getElapsedTime();
    this.core.rotation.y = t * 0.2;
    this.glow.rotation.x = t * 0.15;
    this.glow.rotation.z = t * 0.1;

    const linePos = this.linePositions;
    let offset = 0;
    this.nodePositions = [];

    this.nodes.forEach((group, i) => {
      const { angle, radius, y, speed } = group.userData;
      const a = angle + t * speed;
      const x = Math.cos(a) * radius;
      const z = Math.sin(a) * radius;
      const py = y + Math.sin(t + i) * 0.15;
      group.position.set(x, py, z);
      group.lookAt(0, py, 0);
      this.nodePositions.push({ x, y: py, z });

      const next = this.nodes[(i + 1) % this.nodes.length];
      const nx = next.position.x;
      const ny = next.position.y;
      const nz = next.position.z;

      linePos[offset++] = x;
      linePos[offset++] = py;
      linePos[offset++] = z;
      linePos[offset++] = nx;
      linePos[offset++] = ny;
      linePos[offset++] = nz;

      linePos[offset++] = x;
      linePos[offset++] = py;
      linePos[offset++] = z;
      linePos[offset++] = 0;
      linePos[offset++] = 0;
      linePos[offset++] = 0;
    });

    this.connectionLines.geometry.attributes.position.needsUpdate = true;
    this.renderer.render(this.scene, this.camera);
  }

  dispose() {
    this.renderer.dispose();
  }
}

