export function initScrollAnimations({ onScrollProgress, isMobile = false }) {
  const revealDefaults = {
    y: 36,
    opacity: 0,
    duration: 0.85,
    ease: 'power3.out',
  };

  gsap.utils.toArray('.section').forEach((section) => {
    const targets = section.querySelectorAll('.section__tag, .section__title, .section__text');
    if (!targets.length) return;

    gsap.from(targets, {
      ...revealDefaults,
      stagger: 0.08,
      scrollTrigger: {
        trigger: section,
        start: 'top 78%',
        once: true,
      },
    });
  });

  gsap.from('#about .about-object', {
    scale: 0.85,
    opacity: 0,
    duration: 1,
    ease: 'power3.out',
    scrollTrigger: {
      trigger: '#about',
      start: 'top 72%',
      once: true,
    },
  });

  const pills = document.querySelectorAll('.skill-pills span');
  if (pills.length) {
    gsap.from(pills, {
      y: 16,
      opacity: 0,
      duration: 0.45,
      stagger: 0.03,
      ease: 'power2.out',
      scrollTrigger: {
        trigger: '#skill-pills',
        start: 'top 82%',
        once: true,
      },
    });
  }

  const cards = document.querySelectorAll('.project-card');
  if (cards.length) {
    gsap.from(cards, {
      y: 48,
      opacity: 0,
      duration: 0.75,
      stagger: 0.1,
      ease: 'power3.out',
      scrollTrigger: {
        trigger: '#projects',
        start: 'top 75%',
        once: true,
      },
    });
  }

  gsap.from('.skills-category', {
    y: 24,
    opacity: 0,
    duration: 0.65,
    stagger: 0.08,
    ease: 'power3.out',
    scrollTrigger: {
      trigger: '.skills-categories',
      start: 'top 85%',
      once: true,
    },
  });

  gsap.from('.contact-panel', {
    y: 32,
    opacity: 0,
    duration: 0.9,
    ease: 'power3.out',
    scrollTrigger: {
      trigger: '#contact',
      start: 'top 78%',
      once: true,
    },
  });

  document.querySelectorAll('.glitch-text').forEach((el) => {
    if (el.dataset.glitchPlayed) return;
    ScrollTrigger.create({
      trigger: el,
      start: 'top 82%',
      once: true,
      onEnter: () => {
        if (el.dataset.glitchPlayed) return;
        el.dataset.glitchPlayed = 'true';
        el.classList.add('is-glitching');
        setTimeout(() => el.classList.remove('is-glitching'), 350);
      },
    });
  });

  ScrollTrigger.create({
    trigger: document.documentElement,
    start: 'top top',
    end: 'bottom bottom',
    scrub: true,
    onUpdate: (self) => onScrollProgress?.(self.progress),
  });

  if (!isMobile) {
    const track = document.getElementById('projects-track');
    if (track) {
      track.addEventListener(
        'wheel',
        (e) => {
          if (Math.abs(e.deltaY) <= Math.abs(e.deltaX)) return;
          const max = track.scrollWidth - track.clientWidth;
          if (max <= 0) return;
          const atStart = track.scrollLeft <= 0;
          const atEnd = track.scrollLeft >= max - 1;
          if ((e.deltaY > 0 && !atEnd) || (e.deltaY < 0 && !atStart)) {
            track.scrollLeft += e.deltaY;
            e.preventDefault();
          }
        },
        { passive: false }
      );
    }
  }
}

export function initHeroCTA(scrollFn) {
  const cta = document.getElementById('hero-cta');
  const about = document.getElementById('about');
  cta?.addEventListener('click', () => {
    if (scrollFn) scrollFn(about);
    else about?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  });
}

export function initContactForm() {
  const form = document.getElementById('contact-form');
  form?.addEventListener('submit', (e) => {
    e.preventDefault();
    const btn = form.querySelector('button');
    const original = btn.textContent;
    btn.textContent = 'Transmission sent ✓';
    btn.disabled = true;
    gsap.fromTo(btn, { scale: 1 }, { scale: 1.03, duration: 0.2, yoyo: true, repeat: 1 });
    setTimeout(() => {
      btn.textContent = original;
      btn.disabled = false;
      form.reset();
    }, 3000);
  });
}

